import numpy as np

try:
    from numba import njit

    @njit(cache=True, fastmath=True)
    def _sa_inner(grid, N, target, weights, T, alpha, T_min,
                  max_iter, border, max_density, H, W, seed):
        np.random.seed(seed)
        best_grid = grid.copy()
        best_loss = 0.0
        for y in range(H):
            for x in range(W):
                d = N[y,x] - target[y,x]
                best_loss += weights[y,x] * d * d
        current_loss = best_loss

        history = np.zeros(max_iter // 50000 + 2, dtype=np.float64)
        h_idx = 0
        history[h_idx] = best_loss; h_idx += 1

        for i in range(max_iter):
            y = np.random.randint(0, H)
            x = np.random.randint(0, W)
            if y < border or y >= H - border or x < border or x >= W - border:
                if grid[y, x] == 0:
                    continue
            sign = 1 - 2 * int(grid[y, x])
            d_loss = 0.0
            valid = True
            for dy in range(-1, 2):
                for dx in range(-1, 2):
                    if dy == 0 and dx == 0:
                        continue
                    ny = y + dy; nx = x + dx
                    if 0 <= ny < H and 0 <= nx < W:
                        n_new = N[ny, nx] + sign
                        if n_new < 0.0 or n_new > 8.0:
                            valid = False
                            break
                        diff_new = n_new - target[ny, nx]
                        diff_cur = N[ny, nx] - target[ny, nx]
                        d_loss += weights[ny, nx] * (diff_new*diff_new - diff_cur*diff_cur)
                if not valid:
                    break
            if not valid:
                continue

            if d_loss < 0.0 or np.random.random() < np.exp(-d_loss / (T + 1e-12)):
                grid[y, x] = 1 if sign > 0 else 0
                for dy in range(-1, 2):
                    for dx in range(-1, 2):
                        if dy == 0 and dx == 0:
                            continue
                        ny = y + dy; nx = x + dx
                        if 0 <= ny < H and 0 <= nx < W:
                            N[ny, nx] += sign
                current_loss += d_loss
                if current_loss < best_loss:
                    best_loss = current_loss
                    for yy in range(H):
                        for xx in range(W):
                            best_grid[yy, xx] = grid[yy, xx]

            T = T * alpha
            if T < T_min:
                T = T_min
            if i % 50000 == 0 and i > 0:
                history[h_idx] = best_loss
                h_idx += 1

        return best_grid, best_loss, history[:h_idx]

    NUMBA = True
    print("sa_core: Numba JIT enabled ✓")

except ImportError:
    NUMBA = False

    def _sa_inner(grid, N, target, weights, T, alpha, T_min,
