                    ny,nx = y+dy, x+dx
                    if 0<=ny<H and 0<=nx<W:
                        n_new = Nf[ny,nx]+sign
                        if n_new<0 or n_new>8: ok=False; break
                        d += weights[ny,nx]*((n_new-target[ny,nx])**2-(Nf[ny,nx]-target[ny,nx])**2)
                        ups.append((ny,nx))
                if not ok: break
            if not ok: continue
